class DynamicRecord:
    """Production data container using dynamic attribute binding."""
    def __init__(self, **kwargs):
        for key, value in kwargs.items():
            setattr(self, key, value)

    def __getattr__(self, name):
        return f"[Attribute '{name}' not found]"

# Usage
user = DynamicRecord(id=101, username="dev_lead", role="admin")
print(user.username)  # dev_lead
print(user.salary)    # [Attribute 'salary' not found]

