import pytest

def calculate_discount(price: float, discount: float) -> float:
    if not isinstance(price, (int, float)) or not isinstance(discount, (int, float)):
        raise TypeError('Price and discount must be numeric values.')
    if not (0 <= discount <= 1):
        raise ValueError('Discount must be between 0.0 and 1.0.')
    return price * (1 - discount)

def test_calculate_discount_valid():
    assert calculate_discount(100, 0.2) == 80.0

def test_calculate_discount_type_error():
    with pytest.raises(TypeError):
        calculate_discount('100', 0.2)

